// ─── SÉPARATION ARTICLES RSS / DONNÉES PRIX ───────────────────────────────
const allItems = $input.all();
const articles = allItems.filter(i => i.json.title && i.json.link).slice(0, 25);
const priceItems = allItems.filter(i => i.json.chart);

// ─── EXTRACTION PRIX WTI ET BRENT ─────────────────────────────────────────
let wtiPrice = 'N/D', brentPrice = 'N/D', wtiChg = '0.00', brentChg = '0.00';
for (const p of priceItems) {
  try {
    const r = p.json.chart.result[0];
    const sym = r.meta.symbol;
    const cls = r.indicators.quote[0].close.filter(Boolean);
    const last = cls[cls.length - 1];
    const prev = cls[cls.length - 2] || last;
    const chg = ((last - prev) / prev * 100).toFixed(2);
    if (sym === 'CL=F') { wtiPrice = last.toFixed(2); wtiChg = chg; }
    if (sym === 'BZ=F') { brentPrice = last.toFixed(2); brentChg = chg; }
  } catch (e) {}
}

// ─── DATE DU RAPPORT ───────────────────────────────────────────────────────
const today = new Date().toLocaleDateString('fr-FR', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'Europe/Paris'
});

// ─── GROUPEMENT DES ARTICLES PAR SOURCE ───────────────────────────────────
const grouped = {};
for (const item of articles) {
  let src = 'source';
  try {
    src = new URL(item.json.link).hostname
      .replace('www.', '')
      .replace('feeds.', '')
      .split('.')[0];
  } catch (e) { src = item.json.source || 'unknown'; }
  if (!grouped[src]) grouped[src] = [];
  grouped[src].push(item.json);
}

// ─── CONSTRUCTION DU TEXTE DES ARTICLES ───────────────────────────────────
let articlesText = '';
for (const [src, arts] of Object.entries(grouped)) {
  articlesText += '[SOURCE: ' + src.toUpperCase() + ']\n';
  for (const a of arts.slice(0, 5)) {
    articlesText += '• ' + (a.title || '') + '\n';
    const snippet = a.contentSnippet || a.summary || a.content || '';
    if (snippet) articlesText += '  ' + snippet.substring(0, 150).replace(/\s+/g, ' ') + '\n';
    articlesText += '\n';
  }
  articlesText += '\n';
}

// ─── INDICATEURS DE VARIATION ─────────────────────────────────────────────
const wtiSign  = parseFloat(wtiChg)   >= 0 ? '+' : '';
const brentSign = parseFloat(brentChg) >= 0 ? '+' : '';

// ═══════════════════════════════════════════════════════════════════════════
// SYSTEM PROMPT — GOLDMAN SACHS ANALYST PERSONA
// ═══════════════════════════════════════════════════════════════════════════
const systemPrompt =
  'Tu es un analyste senior, division Global Macro Research & Geopolitical Risk (GMRG). '
  + 'Tu produis des rapports quotidiens de niveau institutionnel destinés à des investisseurs souverains, '
  + 'des family offices et des décideurs stratégiques. '
  + 'TON STYLE: analytique, factuel, précis, quantitatif. Probabilités chiffrées pour chaque scénario. '
  + 'Ton neutre, professionnel, sans jugement de valeur. Indicateurs chiffrés quand disponibles. '
  + 'Pas de généralités — que des analyses concrètes basées sur les données fournies. '
  + 'CONTRAINTE ABSOLUE: Tu réponds UNIQUEMENT en HTML structuré prêt à être inséré dans un email. '
  + 'N\'utilise JAMAIS de balises html, head, body ou style. '
  + 'Utilise uniquement: h2, h3, p, ul, li, strong, table, thead, tbody, tr, th, td, hr, br. '
  + 'Commence directement par le contenu HTML sans aucun texte introductif ni backticks markdown.';

// ═══════════════════════════════════════════════════════════════════════════
// USER PROMPT — STRUCTURE GOLDMAN SACHS (8 sections)
// ═══════════════════════════════════════════════════════════════════════════
const userPrompt =
  'RAPPORT IRAN WAR — GLOBAL MACRO RESEARCH\n'
  + 'Date: ' + today.toUpperCase() + '\n'
  + 'Classification: GUERRE EN IRAN - RAPPORT SUR LES MARCHES ET SITUATION ECONOMQIUE MONDIALES\n'
  + '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n'

  + 'DONNÉES DE MARCHÉ EN TEMPS RÉEL:\n'
  + '• WTI Crude Oil (NYMEX CL=F): ' + wtiPrice + ' USD/baril (' + wtiSign + wtiChg + '% vs J-1)\n'
  + '• Brent Crude (ICE BZ=F):     ' + brentPrice + ' USD/baril (' + brentSign + brentChg + '% vs J-1)\n'
  + '• Spread Brent/WTI: ' + (parseFloat(brentPrice) - parseFloat(wtiPrice)).toFixed(2) + ' USD\n\n'

  + '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n'
  + 'FLUX INFORMATIONNELS DES DERNIÈRES 24H (25 articles max)\n'
  + 'Sources: Reuters, BBC, Al Jazeera, OilPrice.com, Defense News, Dawn, Middle East Eye\n'
  + '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n'
  + articlesText

  + '═══════════════════════════════════════════════\n'
  + 'GÉNÈRE UN RAPPORT HTML AVEC CES 8 SECTIONS OBLIGATOIRES\n'
  + '═══════════════════════════════════════════════\n\n'

  + 'SECTION 1 — <h2>SYNTHÈSE EXÉCUTIVE</h2>\n'
  + '5 bullet points des faits majeurs 24h. Indice Risque Géopolitique Global: X/10 justifié. Signal directionnel pétrole: HAUSSIER/BAISSIER/NEUTRE.\n\n'

  + 'SECTION 2 — <h2>SITUATION OPÉRATIONNELLE IRAN</h2>\n'
  + 'Activités militaires 24h. Arsenal: missiles balistiques (portées), drones Shahed-136/131, capacités navales (mines, FIAC). Fronts actifs. Pertes estimées. Positionnement US CENTCOM, Israël.\n\n'

  + 'SECTION 3 — <h2>MARCHÉS ÉNERGÉTIQUES</h2>\n'
  + 'Analyse technique WTI/Brent: supports/résistances, tendance. DÉTROIT D\'ORMUZ: volume trafic (Mb/j), incidents, probabilité fermeture (%), impact offre mondiale si fermeture 30j. 5ème Flotte US: état alerte. OPEP+: pays affectés. GNL: flux Europe/Asie. Prévision prix pétrole 30j: fourchette USD/baril.\n\n'

  + 'SECTION 4 — <h2>GÉOPOLITIQUE RÉGIONALE</h2>\n'
  + 'Proxies iraniens: Hezbollah, Houthis (frappes mer Rouge, BDTI), milices Irak/Syrie. Pays du Golfe: Aramco, ADNOC, Qatar LNG. Grandes puissances: USA (forces déployées, sanctions), Russie (armes livrées), Chine (importations pétrole iranien). Front israélien: opérations, Iron Dome/Arrow.\n\n'

  + 'SECTION 5 — <h2>CONFLIT PAKISTAN-AFGHANISTAN</h2>\n'
  + 'TTP: frappes transfrontalières, victimes. CPEC: tronçons menacés, investissements à risque (Mrd USD). Gazoducs TAPI: impact approvisionnement. Flux réfugiés. Spillover vers Iran: frontière Sistan-Baloutchistan.\n\n'

  + 'SECTION 6 — <h2>MARCHÉS FINANCIERS & FLUX DE CAPITAUX</h2>\n'
  + 'Devises: DXY, EUR/USD, USD/ILS, USD/SAR, USD/PKR. Actions: MSCI EM, Tadawul, TA-35. Valeurs refuge: XAU/USD (or), Treasuries 10Y, CHF. Matières premières: gaz naturel (TTF/Henry Hub). Indicateurs de peur: VIX, MOVE, CDS souverains Iran/Irak/Liban/Pakistan. Shipping: BDTI, assurances maritimes Golfe.\n\n'

  + 'SECTION 7 — <h2>SCÉNARIOS PROSPECTIFS 30-60-90 JOURS</h2>\n'
  + 'Scénario Base (X%): description + WTI cible + hypothèses + indicateurs confirmation.\n'
  + 'Scénario Escalade Majeure (X%): déclencheur + WTI cible + MSCI EM impact + contagion.\n'
  + 'Scénario Désescalade (X%): médiateurs + WTI cible + timeline.\n\n'

  + 'SECTION 8 — <h2>RECOMMANDATIONS STRATÉGIQUES</h2>\n'
  + 'Allocation tactique par classe actifs (surpondérer/sous-pondérer). Pétrole: entrée long, stop-loss, target 30j/90j. Or XAU: niveau accumulation. Hedging: instruments recommandés. Triggers 72h: 5 indicateurs avancés critiques. Tail risk 5%: scénario + impact maximal chiffré.';

return [{
  json: {
    systemPrompt,
    userPrompt,
    today,
    wtiPrice,
    brentPrice,
    wtiChg,
    brentChg,
    articleCount: articles.length
  }
}];

