const mistralResponse = $input.first().json;
const compileData = $('Code — Compilation & Prompt').first().json;

const today        = compileData.today        || new Date().toLocaleDateString('fr-FR', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const wtiPrice     = compileData.wtiPrice     || 'N/D';
const brentPrice   = compileData.brentPrice   || 'N/D';
const wtiChg       = compileData.wtiChg       || '0.00';
const brentChg     = compileData.brentChg     || '0.00';
const articleCount = compileData.articleCount || 0;

// ── NOUVELLES VARIABLES À AJOUTER ──────────────────────
const goldPrice  = compileData.goldPrice  || 'N/D';
const goldChg    = compileData.goldChg    || '0.00';
const ngPrice    = compileData.ngPrice    || 'N/D';
const ngChg      = compileData.ngChg      || '0.00';
const vixPrice   = compileData.vixPrice   || 'N/D';
const vixChg     = compileData.vixChg     || '0.00';
const eurusd     = compileData.eurusd     || 'N/D';
const eurusdChg  = compileData.eurusdChg  || '0.00';


let rawContent = '<p style="color:#c0392b;font-family:Arial,sans-serif;padding:20px;">⚠️ Erreur: impossible de générer le rapport.</p>';

try {
  if (mistralResponse.choices && mistralResponse.choices[0] && mistralResponse.choices[0].message) {
    let raw = mistralResponse.choices[0].message.content || '';
    raw = raw.replace(/^```html\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
    rawContent = raw;
  } else if (mistralResponse.error) {
    rawContent = '<p style="color:#c0392b;">Erreur API: ' + (mistralResponse.error.message || JSON.stringify(mistralResponse.error)) + '</p>';
  }
} catch(e) {
  rawContent = '<p style="color:#c0392b;">Erreur parsing: ' + e.message + '</p>';
}

const wtiNum    = parseFloat(wtiChg);
const brentNum  = parseFloat(brentChg);
const spreadNum = parseFloat(brentPrice) - parseFloat(wtiPrice);

const wtiColor   = wtiNum   >= 0 ? '#27ae60' : '#c0392b';
const brentColor = brentNum >= 0 ? '#27ae60' : '#c0392b';
const wtiArrow   = wtiNum   >= 0 ? '▲' : '▼';
const brentArrow = brentNum >= 0 ? '▲' : '▼';
const wtiSign    = wtiNum   >= 0 ? '+' : '';
const brentSign  = brentNum >= 0 ? '+' : '';
const dateRef    = new Date().toISOString().split('T')[0];
const rapportNum = dateRef.replace(/-/g, '');

const images = {
  'SYNTH':  'https://loremflickr.com/860/220/iran,war,military?random=' + Date.now(),
  'SITUA':  'https://loremflickr.com/860/220/iran,army,missile?random=' + (Date.now()+1),
  'MARCH':  'https://loremflickr.com/860/220/oil,tanker,gulf?random=' + (Date.now()+2),
  'GÉOPO':  'https://loremflickr.com/860/220/middleeast,geopolitics?random=' + (Date.now()+3),
  'PAKIS':  'https://loremflickr.com/860/220/pakistan,afghanistan,border?random=' + (Date.now()+4),
  'FINAN':  'https://loremflickr.com/860/220/finance,market,trading?random=' + (Date.now()+5),
  'SCENA':  'https://loremflickr.com/860/220/strategy,forecast,risk?random=' + (Date.now()+6),
  'RECOM':  'https://loremflickr.com/860/220/investment,portfolio,gold?random=' + (Date.now()+7)
};

function injectImages(html) {
  let result = html;
  for (const [key, src] of Object.entries(images)) {
    const regex = new RegExp('(<h2[^>]*>[^<]*' + key + '[^<]*<\\/h2>)', 'i');
    const imgBlock =
      '<div style="margin:12px 0 20px 0;border:1px solid #c4bba8;overflow:hidden;border-radius:3px;">'
      + '<img src="' + src + '" style="width:100%;height:200px;object-fit:cover;display:block;" onerror="this.style.display=\'none\'" />'
      + '</div>';
    result = result.replace(regex, '$1' + imgBlock);
  }
  return result;
}

const reportContent = injectImages(rawContent);

const htmlEmail = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>GS Global Macro Research — ${today}</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: Georgia, 'Times New Roman', serif; background: #ece9e0; color: #1a1a1a; padding: 16px; }
    .container { max-width: 900px; margin: 0 auto; background: #ffffff; border: 1px solid #c4bba8; box-shadow: 0 4px 24px rgba(0,0,0,0.15); }
    .gs-header { background: linear-gradient(135deg, #0d1e3a 0%, #1a3460 100%); padding: 28px 40px; border-bottom: 4px solid #b8962e; }
    .gs-header-top { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 12px; }
    .gs-brand { color: #b8962e; font-size: 24px; font-weight: 900; letter-spacing: 4px; font-family: Arial, sans-serif; }
    .gs-classif { background: #b8962e; color: #0d1e3a; font-size: 10px; font-weight: 900; padding: 5px 12px; letter-spacing: 1.5px; border-radius: 2px; font-family: Arial, sans-serif; white-space: nowrap; }
    .gs-title { color: #ffffff; font-size: 17px; font-weight: 600; margin-bottom: 4px; letter-spacing: 0.4px; }
    .gs-subtitle { color: #7aaccc; font-size: 12px; letter-spacing: 0.3px; }
    .gs-datebar { background: #162d52; padding: 9px 40px; color: #b8962e; font-size: 11.5px; font-weight: 700; letter-spacing: 0.8px; border-bottom: 1px solid rgba(184,150,46,0.35); font-family: Arial, sans-serif; }
    .gs-sources { background: #0f1e38; padding: 6px 40px; font-size: 10px; color: #5a7a9a; letter-spacing: 0.4px; font-family: Arial, sans-serif; border-bottom: 1px solid #1e3458; }
    .gs-market { display: flex; background: #f5f2eb; border-bottom: 2px solid #c4bba8; }
    .gs-tile { flex: 1; padding: 16px 18px; text-align: center; border-right: 1px solid #c4bba8; }
    .gs-tile:last-child { border-right: none; }
    .gs-tile-label { font-size: 10px; color: #888; text-transform: uppercase; letter-spacing: 1.2px; font-family: Arial, sans-serif; margin-bottom: 5px; }
    .gs-tile-price { font-size: 22px; font-weight: 700; color: #0d1e3a; font-family: Arial, sans-serif; }
    .gs-tile-change { font-size: 12px; font-weight: 700; font-family: Arial, sans-serif; margin-top: 3px; }
    .gs-tile-unit { font-size: 10px; color: #999; font-family: Arial, sans-serif; margin-top: 2px; }
    .gs-body { padding: 30px 40px; }
    .gs-body h2 { color: #0d1e3a; font-size: 12.5px; font-weight: 800; text-transform: uppercase; letter-spacing: 1.5px; border-left: 5px solid #b8962e; padding: 7px 0 7px 14px; margin: 28px 0 0 0; font-family: Arial, sans-serif; background: linear-gradient(90deg, rgba(184,150,46,0.07) 0%, transparent 100%); }
    .gs-body h3 { color: #1a3460; font-size: 11.5px; font-weight: 700; margin: 14px 0 5px 0; letter-spacing: 0.5px; font-family: Arial, sans-serif; text-transform: uppercase; }
    .gs-body p { font-size: 13.5px; line-height: 1.85; color: #2a2a2a; margin-bottom: 10px; }
    .gs-body ul { padding-left: 22px; margin-bottom: 12px; }
    .gs-body li { font-size: 13.5px; line-height: 1.8; color: #2a2a2a; margin-bottom: 5px; }
    .gs-body strong { color: #0d1e3a; }
    .gs-body table { width: 100%; border-collapse: collapse; margin: 14px 0; font-size: 12.5px; }
    .gs-body th { background: #0d1e3a; color: #b8962e; padding: 8px 12px; text-align: left; font-family: Arial, sans-serif; font-size: 11px; letter-spacing: 0.5px; }
    .gs-body td { padding: 7px 12px; border-bottom: 1px solid #e8e4db; color: #333; }
    .gs-body tr:nth-child(even) td { background: #f8f6f0; }
    .gs-body hr { border: none; border-top: 1px solid #ddd7c8; margin: 18px 0; }
    .gs-footer { background: #0d1e3a; padding: 22px 40px; text-align: center; border-top: 3px solid #b8962e; }
    .gs-footer p { color: #5a7a9a; font-size: 10px; line-height: 2.1; font-family: Arial, sans-serif; }
    .gs-footer strong { color: #b8962e; }
  </style>
</head>
<body>
<div class="container">

  <div class="gs-header">
    <div class="gs-header-top">
      <div class="gs-brand">IRANIAN WAR REPORT</div>
      <div class="gs-classif">⚠&nbsp; RAPPORT ÉCONOMIQUE STRATÉGIQUE</div>
    </div>
    <div class="gs-title">Global Macro Research &amp; Geopolitical Risk Division</div>
    <div class="gs-subtitle">Rapport Quotidien — Conflit Iranien &amp; Retombées Économiques Mondiales | Pakistan-Afghanistan</div>
  </div>

  <div class="gs-datebar">
    📅&nbsp; ${today.toUpperCase()}&nbsp;&nbsp;|&nbsp;&nbsp;MISE À JOUR: 06H00 CET&nbsp;&nbsp;|&nbsp;&nbsp;RÉFERENCE: GMRG-IRAN-${rapportNum}
  </div>

  <div class="gs-sources">
    📡 Sources: Reuters · BBC · Al Jazeera · OilPrice.com · Defense News · Dawn · Middle East Eye · Yahoo Finance — <strong style="color:#7aaccc;">${articleCount} articles analysés</strong>
  </div>

  <div class="gs-market">
    <div class="gs-tile">
      <div class="gs-tile-label">WTI Crude Oil</div>
      <div class="gs-tile-price">$${wtiPrice}</div>
      <div class="gs-tile-change" style="color:${wtiColor}">${wtiArrow}&nbsp;${wtiSign}${wtiChg}%</div>
      <div class="gs-tile-unit">USD/baril · NYMEX CL=F</div>
    </div>
    <div class="gs-tile">
      <div class="gs-tile-label">Brent Crude</div>
      <div class="gs-tile-price">$${brentPrice}</div>
      <div class="gs-tile-change" style="color:${brentColor}">${brentArrow}&nbsp;${brentSign}${brentChg}%</div>
      <div class="gs-tile-unit">USD/baril · ICE BZ=F</div>
    </div>
    <div class="gs-tile">
      <div class="gs-tile-label">Spread Brent/WTI</div>
      <div class="gs-tile-price" style="font-size:19px;">$${isNaN(spreadNum) ? 'N/D' : Math.abs(spreadNum).toFixed(2)}</div>
      <div class="gs-tile-change" style="color:#888;">Brent Premium</div>
      <div class="gs-tile-unit">USD/baril</div>
    </div>
  </div>

  <div class="gs-body">
    ${reportContent}
  </div>

  <div class="gs-footer">
    <p>
      <strong>Global Macro Research &amp ; Geopolitical Risk Division - IRAN WAR</strong><br>
      Ce rapport est fourni à titre informatif uniquement et ne constitue pas un conseil en investissement,
      une offre ou une sollicitation d'achat ou de vente de tout instrument financier.<br>
      Les performances passées ne préjugent pas des performances futures.
      Les projections sont basées sur des modèles internes sujets à révision sans préavis.<br>
    </p>
  </div>

</div>
</body>
</html>`;

const subject =
  '🔴 IRANIAN WAR REPORT — '
  + new Date().toLocaleDateString('fr-FR', { day: '2-digit', month: 'short', year: 'numeric' }).toUpperCase()
  + ' | WTI: $' + wtiPrice
  + ' (' + wtiSign + wtiChg + '%)'
  + ' | Brent: $' + brentPrice
  + ' (' + brentSign + brentChg + '%)'
  + ' | Ormuz Risk Alert';

return [{
  json: {
    htmlBody: htmlEmail,
    subject:  subject,
    to:       'REMPLACER@VOTREDOMAINE.COM'
  }
}];
